Given the following code, what is the console output order?

console.log('A');
setTimeout(() => console.log('B'), 0);
Promise.resolve().then(() => console.log('C'));
console.log('D');

What does this code output? Explain each step.

async function foo() {
  console.log('1');
  await Promise.resolve();
  console.log('2');
}

console.log('3');
foo();
console.log('4');

Predict the full console output and explain why:

console.log('start');

setTimeout(() => {
  console.log('timeout 1');
  Promise.resolve().then(() => console.log('promise inside timeout'));
}, 0);

Promise.resolve()
  .then(() => {
    console.log('promise 1');
    setTimeout(() => console.log('timeout inside promise'), 0);
  })
  .then(() => console.log('promise 2'));

console.log('end');

You are reviewing a PR for a high-traffic analytics dashboard. A teammate has written the following to batch DOM updates:

function batchUpdates(items) {
  items.forEach(item => {
    Promise.resolve().then(() => updateDOM(item));
  });
}

The dashboard has 500 items and updateDOM triggers layout reads (getBoundingClientRect). Your teammate argues 'Promises are async so this won't block the UI.' Are they correct? What would you recommend instead, and why?
